// composable
function useChart(data: { name: string, visual_data: VisualData }) {
  function drawCharts() {
    for (const section of allSections) {
      const config = section.buildChartConfig({
        visualData: data.visual_data, // ← reactive 物件的 reference
        // ...
      })
      new Chart(ctx, config)
    }
  }
  return { drawCharts }
}

